import React, { useState, useEffect } from "react";
import { useProducts } from "../context/ProductContext";
import SearchBar from "../PriceManagementPage/SearchBar";
import EditablePriceTable, { TableProduct } from "./EditablePriceTable";
import "./PriceManagementPage.css";

export default function PriceManagementPage() {
    const { products, updateProductPrice, deleteProduct } = useProducts();

    const [searchResults, setSearchResults] = useState<TableProduct[]>([]);

    useEffect(() => {
        // map your context products → table products
        const data = products.map(p => ({
            id: p.id,
            name: p.name,
            currentPrice: p.price,
        }));
        setSearchResults(data);
    }, [products]);

    const handleSearch = (query: string) => {
        const q = query.trim().toLowerCase();
        if (!q) {
            return setSearchResults(products.map(p => ({
                id: p.id,
                name: p.name,
                currentPrice: p.price,
            })));
        }
        setSearchResults(
            products
                .filter(p => p.name.toLowerCase().includes(q))
                .map(p => ({
                    id: p.id,
                    name: p.name,
                    currentPrice: p.price,
                }))
        );
    };

    const handlePriceUpdate = (id: number, newPrice: number) => {
        updateProductPrice(id, newPrice);
    };

    const handleDelete = (id: number) => {
        deleteProduct(id);
    };

    return (
        <div className="price-management-container">
            <h2>Real-Time Pricing</h2>

            <SearchBar onSearch={handleSearch} placeholder="Ürün ara…" />

            <EditablePriceTable
                products={searchResults}
                onPriceUpdate={handlePriceUpdate}
                onDelete={handleDelete}
            />
        </div>
    );
}
